import React, { useEffect, useState, useMemo } from 'react';
import { TransactionType, StockItem, Brand, TransactionStatus } from '../types';
import { createBulkTransactions, fetchTransactions } from '../services/transactionService';
import { fetchInventory } from '../services/inventoryService';
import { 
  Search,
  Loader2,
  Trash2,
  Minus,
  Plus,
  ShoppingCart,
  PackagePlus,
  Percent,
  Sparkles,
  CircleSlash,
  X,
  Check,
  Box,
  ArrowRight,
  User as UserIcon,
  ShieldCheck,
  Calendar,
  Banknote,
  Wallet
} from 'lucide-react';

const fd = (n: number | string) => {
  const num = parseInt(n.toString()) || 0;
  return num >= 0 && num < 10 ? `0${num}` : `${num}`;
};

const DailyTransactions: React.FC<any> = ({ user, forcedMode }) => {
  // Fix: Standardized mode to match TransactionType.SALE ('SALE') instead of 'SALES'
  const [mode, setMode] = useState<TransactionType>(forcedMode === 'SALES' ? TransactionType.SALE : (forcedMode || TransactionType.SALE));
  const [inventory, setInventory] = useState<StockItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [cart, setCart] = useState<any[]>([]);
  const [search, setSearch] = useState('');
  const [suggestions, setSuggestions] = useState<StockItem[]>([]);
  const [customerName, setCustomerName] = useState('');
  const [selectedBrand, setSelectedBrand] = useState<Brand | 'ALL'>('ALL');
  const [isPaid, setIsPaid] = useState(false); // Toggle for instant payment record

  // Backdating state: defaults to current date in ISO format for datetime-local
  const [transactionDate, setTransactionDate] = useState<string>(() => {
    const now = new Date();
    // Format to YYYY-MM-DDTHH:mm for datetime-local input
    return new Date(now.getTime() - now.getTimezoneOffset() * 60000).toISOString().slice(0, 16);
  });

  const loadBaseData = async () => {
    const [inv] = await Promise.all([fetchInventory()]);
    setInventory(inv);
  };

  useEffect(() => { loadBaseData(); }, [mode]);

  const handleSearch = (val: string) => {
    setSearch(val);
    if (val.length > 0) {
       let filtered = inventory.filter(i => 
         i.partNumber.toLowerCase().includes(val.toLowerCase()) || 
         i.name.toLowerCase().includes(val.toLowerCase())
       );
       if (selectedBrand !== 'ALL') filtered = filtered.filter(i => i.brand === selectedBrand);
       setSuggestions(filtered.slice(0, 30));
    } else setSuggestions([]);
  };

  const addToCart = (item: StockItem) => {
      const existing = cart.find(c => c.partNumber === item.partNumber);
      if (existing) { 
          updateQty(existing.tempId, 1); 
          resetSearch(); 
          return; 
      }

      const initialDiscount = mode === TransactionType.PURCHASE ? (item.brand === Brand.MAHINDRA ? 19.36 : 12) : 0;
      const newItem = {
          tempId: Math.random().toString(36).substring(2),
          partNumber: item.partNumber,
          name: item.name, 
          type: mode,
          quantity: 1,
          mrp: item.price,
          discount: initialDiscount,
          price: item.price * (1 - initialDiscount / 100),
          customerName: customerName,
          brand: item.brand,
          stockLevel: item.quantity
      };
      setCart(prev => [...prev, newItem]); 
      resetSearch();
  };

  const resetSearch = () => { setSearch(''); setSuggestions([]); };

  const updateQty = (id: string, delta: number) => {
      setCart(prev => prev.map(item => {
          if (item.tempId === id) {
              let newQty = Math.max(1, item.quantity + delta);
              if (mode === TransactionType.SALE && newQty > item.stockLevel) newQty = item.stockLevel;
              return { ...item, quantity: newQty };
          }
          return item;
      }));
  };

  const updateQtyDirect = (id: string, value: string) => {
      const val = parseInt(value) || 0;
      setCart(prev => prev.map(item => {
          if (item.tempId === id) {
              let newQty = val;
              if (mode === TransactionType.SALE && newQty > item.stockLevel) newQty = item.stockLevel;
              return { ...item, quantity: newQty };
          }
          return item;
      }));
  };

  const updatePriceInfo = (id: string, field: 'mrp' | 'discount', value: string) => {
      const val = parseFloat(value) || 0;
      setCart(prev => prev.map(item => {
          if (item.tempId === id) {
              const updated = { ...item, [field]: val };
              updated.price = updated.mrp * (1 - updated.discount / 100);
              return updated;
          }
          return item;
      }));
  };

  const handleSubmit = async () => {
    if (cart.length === 0) return;
    setLoading(true);

    // Create timestamp from selected date
    const finalCreatedAt = new Date(transactionDate).toISOString();

    const payload = cart.map(item => ({
       partNumber: item.partNumber,
       type: mode,
       quantity: item.quantity,
       price: item.price,
       // Rule: If SALE and isPaid toggle is on, record full price as paid. Otherwise 0 (Credit).
       // Rule: For PURCHASE/RETURN, always record as paid/settled by default.
       paidAmount: mode === TransactionType.SALE 
          ? (isPaid ? item.price * item.quantity : 0) 
          : (item.price * item.quantity),
       customerName: customerName || 'Walk-in',
       createdByRole: user.role,
       createdByName: user.name,
       createdAt: finalCreatedAt
    }));

    const res = await createBulkTransactions(payload);
    setLoading(false);
    if (res.success) {
      setCart([]);
      setCustomerName('');
      setIsPaid(false); // Reset toggle after success
      alert("Session committed successfully with date: " + new Date(transactionDate).toLocaleString());
    } else {
      alert("Failed to commit: " + res.message);
    }
  };

  const totalAmount = useMemo(() => cart.reduce((sum, item) => sum + (item.quantity * item.price), 0), [cart]);
  const accentColor = mode === TransactionType.RETURN ? 'bg-rose-600' : mode === TransactionType.PURCHASE ? 'bg-slate-900' : 'bg-blue-600';

